    /// <summary>
    ///
    /// </summary>
    /// </summary>
    public void postLoad()
    {
        super();



        // Variable declarations
        ExchangeRateUnionView exchangeRateUnionView;
        CurrencyExchangeHelper currencyExchangeHelper;
        AmountMst convertedAmount;
        AmountMST amtUSD;
        CurrencyCode fromCurrency = this.CurrecyLC; // Note spelling fix from 'CurrecyLC' to 'CurrencyLC' if needed
        CurrencyCode toCurrency = 'USD';
        AmountMst amountToConvert = this.CostAmountAdjustment + this.CostAmountPosted;
        TransDate transactionDate = systemDateGet();

        // Determine exchange rate in USD
        if (this.CurrencyCode == 'USD')
        {
            this.ExchInUSD = 1;
        }
        else
        {
            // Try direct rate: Currency -> USD
            select firstonly exchangeRateUnionView
        order by exchangeRateUnionView.ValidFrom desc
        where exchangeRateUnionView.FromCurrencyCode == this.CurrencyCode
            && exchangeRateUnionView.ToCurrencyCode == 'USD'
            && exchangeRateUnionView.ValidFrom <= this.DateFinancial
            && exchangeRateUnionView.ValidTo >= this.DateFinancial;

            if (exchangeRateUnionView)
            {
                this.ExchInUSD = exchangeRateUnionView.ExchangeRate / 100.0;
            }
            else
            {
                // Try reverse rate: USD -> Currency (invert)
                select firstonly exchangeRateUnionView
            order by exchangeRateUnionView.ValidFrom desc
            where exchangeRateUnionView.FromCurrencyCode == 'USD'
                && exchangeRateUnionView.ToCurrencyCode == this.CurrencyCode
                && exchangeRateUnionView.ValidFrom <= this.DateFinancial
                && exchangeRateUnionView.ValidTo >= this.DateFinancial;

                if (exchangeRateUnionView && exchangeRateUnionView.ExchangeRate != 0)
                {
                    this.ExchInUSD = 100.0 / exchangeRateUnionView.ExchangeRate;
                }
                else
                {
                    this.ExchInUSD = 0; // Fallback if no rate found
                }
            }
        }

        // Use CurrencyExchangeHelper to convert amount from local currency to USD
        currencyExchangeHelper = CurrencyExchangeHelper::newExchangeDate(Ledger::current(), transactionDate);

        convertedAmount = currencyExchangeHelper.calculateCurrencyToCurrency(
    toCurrency,
    fromCurrency,
    amountToConvert,
    true
);

        this.AmountInUSD = convertedAmount;

        ExchangeRateUnionView ExchangeRateUnionViewLoc;


        select firstonly  ExchangeRateUnionViewLoc
            order by ExchangeRateUnionViewLoc.ValidFrom desc
      where ExchangeRateUnionViewLoc.FromCurrencyCode == this.CurrencyCode && ExchangeRateUnionViewLoc.ToCurrencyCode == Ledger::accountingCurrency(CompanyInfo::current())
      && ExchangeRateUnionViewLoc.ValidFrom <= this.DateFinancial &&  ExchangeRateUnionViewLoc.ValidTo >=this.DateFinancial;

        if (this.CurrencyCode == Ledger::accountingCurrency(CompanyInfo::current() ))
        {
            this.ExchInLC   = 1;
        }
        else

        {
            this.ExchInLC = (ExchangeRateUnionViewLoc.ExchangeRate)/100.00;
        }

        DataArea dataArea;
        select firstonly Name from dataArea
            where dataArea.id       == this.DataAreaId;

        this.EntityName             = dataArea.name;

        InventItemGroupItem inventModelGroupItem;
        InventItemGroup    inventItemGroup;

        //select firstonly Name
        //    from inventItemGroup
        //        join inventModelGroupItem
        //        where inventModelGroupItem.ItemId == this.ItemId
        //            && inventItemGroup.itemGroupId == inventModelGroupItem.ModelGroupId;

        select firstonly inventModelGroupItem where inventModelGroupItem.ItemId == this.itemid;

        select firstonly Name from inventItemGroup where inventItemGroup.ItemGroupId == inventModelGroupItem.itemgroupid;

        this.InventItemModelGroup = inventItemGroup.Name;

        ETG_InventFairValueLineTable    inventFairValueLineTable  ;
        ETG_InventFairValueHeaderTable  inventFairValueHeaderTable;

        select firstonly fairvalue from  inventFairValueLineTable
            join inventFairValueHeaderTable
            where inventFairValueHeaderTable.JournalDate == this.DateFinancial
             && inventFairValueLineTable.FairValuationSerialNumber == inventFairValueHeaderTable.FairValuationSerialNumber
             && inventFairValueLineTable.ItemNumber == this.ItemId;

        this.FairValue = inventFairValueLineTable.fairValue;

        ModuleInventPurchSales typeId;

        if (this.ReferenceCategory == InventTransType::Sales)
        {
            typeId =  ModuleInventPurchSales::Sales;
        }
        else if (this.ReferenceCategory == InventTransType::Purch)
        {
            typeId =  ModuleInventPurchSales::Purch;
        }
        else
        {
            typeId =  ModuleInventPurchSales::Invent;
        }

        this.UnitId = InventTableModule::find(this.ItemId, typeId).UnitId;
        this.CurrecyLC      = Ledger::accountingCurrency();

    }

public static str latestExchangeRate()
{
    str sqlExpr = @"
    (
        SELECT TOP 1 (ER.ExchangeRate)/100
        FROM ExchangeRateUnionView AS ER
        WHERE ER.FromCurrencyCode ='USD'
          AND ER.ToCurrencyCode = 'AED'
        ORDER BY ER.ValidFrom DESC
    )";
    return sqlExpr;
}
